INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "青空の下で謁見", "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 40, 2834, "ペコリーヌとの出会い", "フリーマーケット会場", 2, 0, 5118061, 1, 91002, 8, 10118, 7);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "未来の騎空団\nマスコット？", "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 40, 2835, "マホとの出会い", "フリーマーケット会場", 2, 0, 5118062, 1, 91002, 8, 10118, 7);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "お嬢さまからの\n緊急依頼", "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 40, 2837, "アキノとの出会い", "ランドソル市街地", 2, 0, 5118063, 1, 91002, 8, 10118, 7);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "黄金色の悩みごと", "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 40, 4108402, "ジュンとの出会い", "フリーマーケット会場", 2, 0, 5118064, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "白熱！　格闘大会！", "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 40, 4107402, "カオリとの出会い", "フリーマーケット会場", 2, 0, 5118065, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "祭り太鼓はオーエドの華", "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 40, 9000227, "ニノンとの出会い", "オーエド町", 2, 1, 5118066, 1, 91002, 8, 10118, 16);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "人気者は遅れて\nやってくる", "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 40, 2101181, "スズナとの出会い", "フリーマーケット会場", 3, 0, 5118067, 1, 91002, 8, 10118, 19);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "巫女・ミーツ・魔法少女", "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 40, 4109402, "ナナカとの出会い", "ランドソル市街地", 3, 0, 5118068, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "ネズ耳は二度なくなる", "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 40, 4305402, "キャル＆コッコロとの出会い", "フリーマーケット会場", 3, 0, 5118069, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "この出会いにカンパイ！", "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 40, 4101402, "ユカリとの出会い", "ランドソル市街地", 3, 0, 5118070, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "陰陽アンサンブル", "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 40, 4106402, "アオイとの出会い", "ランドソル市街地", 3, 0, 5118071, 1, 91002, 8, 10118, 18);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "運試し十番勝負！", "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 40, 2836, "シノブとの出会い", "フリーマーケット会場", 3, 1, 5118072, 1, 91002, 8, 10118, 7);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (20063115, "彼女たちの新たな日常", 0, 0, 0, "オープニング", 0, 1, 0, 5118600, 0, 0, 0, 10118, 0);
